(()=>{
const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const cfg=window.HP_CONFIG||{};
const ready=cfg.SUPABASE_URL&&!cfg.SUPABASE_URL.includes('YOUR_')&&window.supabase;
const sb=ready?window.supabase.createClient(cfg.SUPABASE_URL,cfg.SUPABASE_ANON_KEY):null;
const categories=['Tractors','Combine Harvesters','Straw Reapers','Seed Drills','Rotavators','Cultivators','Balers','Sprayers','Irrigation Systems','Smart Farming','Spare Parts','Tyres & Engines','Harvesters','Threshers','Loaders','Trailers'];
const states=['Andhra Pradesh','Arunachal Pradesh','Assam','Bihar','Chhattisgarh','Goa','Gujarat','Haryana','Himachal Pradesh','Jharkhand','Karnataka','Kerala','Madhya Pradesh','Maharashtra','Manipur','Meghalaya','Mizoram','Nagaland','Odisha','Punjab','Rajasthan','Sikkim','Tamil Nadu','Telangana','Tripura','Uttar Pradesh','Uttarakhand','West Bengal','Delhi','Jammu and Kashmir','Ladakh'];
const brands=['Mahindra','Swaraj','Sonalika','John Deere','New Holland','Massey Ferguson','Eicher','Kubota','Preet','Claas','Shaktiman','Fieldking','Dasmesh','Landforce','Other'];
const PLAN_LIST=[['Starter',999,5,'Basic seller access'],['Growth',2999,20,'More listings'],['Dealer',4999,50,'Dealer profile'],['Premium',7999,100,'Featured placement ready'],['Elite',11999,200,'Priority visibility'],['Royal',15999,9999,'Top dealer branding']];
let S={session:null,user:null,profile:null,seller:null,products:[],cart:JSON.parse(localStorage.hp_cart||'[]'),filters:{q:'',category:'',state:'',brand:'',type:''},counts:{products:0,sellers:0,districts:0},unread:0,sub:null};
const authId=()=>S.user?.id||S.profile?.auth_id||null;
const profileDbId=()=>S.profile?.id||null;
const money=n=>'₹'+Number(n||0).toLocaleString('en-IN');
const fallback=t=>`https://placehold.co/1200x850/f7f2e8/0f2b1d?text=${encodeURIComponent(t||'Harvester Parts')}`;
const img=(src,t)=>src||fallback(t);
const toast=m=>{let t=$('#toast'); if(!t)return; t.textContent=m; t.classList.add('show'); setTimeout(()=>t.classList.remove('show'),2600)};
function showLoading(msg='Processing...'){const o=$('#loadingOverlay'),t=$('#loadingText'); if(t)t.textContent=msg; if(o){o.classList.add('show');o.setAttribute('aria-hidden','false')}}
function hideLoading(){const o=$('#loadingOverlay'); if(o){o.classList.remove('show');o.setAttribute('aria-hidden','true')}}
async function withLoading(msg,fn){showLoading(msg); try{return await fn()} finally{hideLoading()}}

const isAdmin=()=>String(S.profile?.role||'').toLowerCase()==='admin'||(cfg.ADMIN_EMAIL&&S.user?.email===cfg.ADMIN_EMAIL);
const isSeller=()=>isAdmin()||S.seller?.status==='approved'||['seller','dealer'].includes(String(S.profile?.role||'').toLowerCase());
function esc(s){return String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function saveCart(){localStorage.hp_cart=JSON.stringify(S.cart); updateCart()}
function updateCart(){const c=$('#cartCount'); if(c)c.textContent=S.cart.reduce((a,b)=>a+(b.qty||1),0)}
async function init(){setTimeout(()=>$('#intro')?.classList.add('hide'),700); bindGlobal(); await auth(); await loadProducts(); await loadCounts(); route(); if('serviceWorker'in navigator) navigator.serviceWorker.register('sw.js').catch(()=>{})}
function bindGlobal(){ $('#menuBtn').onclick=openDrawer; $$('[data-close]').forEach(b=>b.onclick=closeDrawer); $('#accountBtn').onclick=()=>S.user?location.hash='account':authModal(); $('#cartBubble').onclick=()=>location.hash='cart'; $('#scrollTop').onclick=()=>scrollTo({top:0,behavior:'smooth'}); document.body.onclick=e=>{let b=e.target.closest('[data-route]'); if(b){e.preventDefault(); location.hash=b.dataset.route}}; addEventListener('hashchange',route); addEventListener('scroll',()=>$('#scrollTop')?.classList.toggle('show',scrollY>500),{passive:true}); }
async function auth(){ if(!sb)return; const {data}=await sb.auth.getSession(); S.session=data.session; S.user=data.session?.user||null; if(S.user) await loadProfile(); watchRealtime(); sb.auth.onAuthStateChange(async(_,session)=>{S.session=session;S.user=session?.user||null;if(S.user)await loadProfile();else{S.profile=null;S.seller=null} watchRealtime(); updateHeader(); route();}); }
async function loadProfile(){
  if(!sb||!S.user)return;
  let {data,error}=await sb.from('users').select('*').eq('auth_id',S.user.id).maybeSingle();
  if(error) console.warn(error);
  if(!data){
    await sb.from('users').insert({auth_id:S.user.id,email:S.user.email,phone:S.user.phone,full_name:S.user.user_metadata?.full_name||'',user_uid:'HP-'+S.user.id.replaceAll('-','').slice(0,8).toUpperCase()});
    ({data}=await sb.from('users').select('*').eq('auth_id',S.user.id).maybeSingle());
  }
  const adminEmail=String(cfg.ADMIN_EMAIL||'kiratveersinghralhan@gmail.com').toLowerCase();
  if(S.user.email && S.user.email.toLowerCase()===adminEmail && data?.role!=='admin'){
    await sb.from('users').update({role:'admin'}).eq('auth_id',S.user.id);
    ({data}=await sb.from('users').select('*').eq('auth_id',S.user.id).maybeSingle());
  }
  S.profile=data;
  await loadSeller();
  await loadUnread();
}
async function loadSeller(){ if(!sb||!S.profile){S.seller=null;return} const {data}=await sb.from('sellers').select('*').eq('user_id',authId()).maybeSingle(); S.seller=data||null; }
async function loadProducts(){ if(!sb){S.products=[];return} const {data,error}=await sb.from('products').select('*').eq('status','approved').order('created_at',{ascending:false}); if(error){console.warn(error); S.products=[]} else S.products=data||[]; }
async function loadCounts(){ if(!sb){S.counts={products:0,sellers:0,districts:0};return} const [p,s,d]=await Promise.all([sb.from('products').select('id',{count:'exact',head:true}).eq('status','approved'),sb.from('sellers').select('id',{count:'exact',head:true}).eq('status','approved'),sb.from('products').select('district').eq('status','approved')]); S.counts={products:p.count||0,sellers:s.count||0,districts:new Set((d.data||[]).map(x=>x.district).filter(Boolean)).size}; }
async function loadUnread(){ if(!sb||!S.profile)return; const {count}=await sb.from('notifications').select('id',{count:'exact',head:true}).eq('user_id',authId()).eq('is_read',false); S.unread=count||0; updateHeader(); }
function watchRealtime(){ if(S.sub){sb?.removeChannel(S.sub); S.sub=null} if(!sb||!S.user)return; S.sub=sb.channel('hp-live-'+authId()).on('postgres_changes',{event:'INSERT',schema:'public',table:'messages',filter:`receiver_id=eq.${authId()}`},()=>{toast('New message received');loadUnread();}).on('postgres_changes',{event:'INSERT',schema:'public',table:'notifications',filter:`user_id=eq.${authId()}`},p=>{toast(p.new?.title||'New notification');loadUnread();}).subscribe(); }
function updateHeader(){ $('#accountBtn').textContent=S.user?'Account':'Login'; let badge=$('#notifBadge'); if(badge)badge.textContent=S.unread||''; updateCart(); }
function route(){closeDrawer(); const [r,param]=(location.hash.replace('#','')||'home').split('/'); const views={home,marketplace,product,sell,plans,badges,cart,checkout,account,dashboard,orders,messages,notifications,storefront,admin,reports,policy,wishlist,ai}; $('#app').innerHTML=(views[r]||home)(param); setTimeout(afterRender,20); updateMeta(r,param); updateHeader();}
function afterRender(){reveal(); counters(); bindPage();}

function setMeta(name,value,prop=false){let sel=prop?`meta[property="${name}"]`:`meta[name="${name}"]`;let el=$(sel);if(!el){el=document.createElement('meta');el.setAttribute(prop?'property':'name',name);document.head.appendChild(el)}el.setAttribute('content',value)}
function updateMeta(r,param){
  let title='Harvester Parts — Buy & Sell Agricultural Machinery, Spare Parts and Farm Equipment';
  let desc='Harvester Parts is a verified agriculture marketplace for tractors, harvesters, seeding drills, implements, spare parts and machinery deals across India.';
  let url=location.href.split('#')[0]+(location.hash||'');
  if(r==='product'){
    let p=S.products.find(x=>String(x.id)===String(param));
    if(p){title=`${p.title} for Sale ${p.district?`in ${p.district}`:''} — Harvester Parts`; desc=`Buy ${p.title} ${p.brand?`by ${p.brand}`:''}. Price ${money(p.price)}. Verified agri marketplace with seller messaging, checkout and product reviews.`;}
  }else if(r==='marketplace'){title='Marketplace — Tractors, Harvesters, Spare Parts & Farm Machines | Harvester Parts';desc='Browse verified listings for agricultural machinery, tractor parts, combine harvesters, seed drills, rotavators and spare parts.'}
  else if(r==='sell'){title='Sell Agricultural Machinery & Spare Parts — Harvester Parts';desc='Become a verified seller and post tractors, harvesters, implements and spare parts on Harvester Parts.'}
  else if(r==='badges'){title='Trust Badges & Rewards — Harvester Parts';desc='Earn verified seller, trusted dealer, fast responder and top rated badges on Harvester Parts.'}
  document.title=title;setMeta('description',desc);setMeta('og:title',title,true);setMeta('og:description',desc,true);setMeta('og:url',url,true);setMeta('twitter:title',title);setMeta('twitter:description',desc);
}

function reveal(){let items=$$('.hero,.stat,.card,.product,.form-card,.legal,.cart-row,.admin-card,.section'); if(!('IntersectionObserver'in window)){items.forEach(i=>i.classList.add('in'));return} const io=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)e.target.classList.add('in')}),{threshold:.12}); items.forEach(i=>{i.classList.add('reveal');io.observe(i)})}
function counters(){$$('.stat b[data-count]').forEach(el=>{if(el.dataset.done)return; const run=()=>{el.dataset.done=1;let target=+el.dataset.count,st=performance.now(); const tick=n=>{let p=Math.min(1,(n-st)/1000),e=1-Math.pow(1-p,3);el.textContent=Math.round(target*e).toLocaleString('en-IN'); if(p<1)requestAnimationFrame(tick)};requestAnimationFrame(tick)}; new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)run()}),{threshold:.3}).observe(el)})}
function home(){return `<section class="hero"><div><p class="eyebrow">Verified Agri Marketplace</p><h1>Buy and sell agricultural machines and spare parts.</h1><p>Harvester Parts connects farmers, buyers, verified sellers and dealers with live listings, secure spare-parts checkout and enquiry flow for high-value machinery.</p><div class="hero-actions"><button class="btn" data-route="marketplace">Browse Marketplace</button><button class="ghost" data-route="sell">Start Selling</button></div></div><div class="hero-img"></div></section><section class="stats"><div class="stat"><b data-count="${S.counts.products}">0</b> <span>Live Products</span></div><div class="stat"><b data-count="${S.counts.sellers}">0</b> <span>Verified Sellers</span></div><div class="stat"><b data-count="${S.counts.districts}">0</b> <span>Active Districts</span></div></section><section class="section"><p class="eyebrow">Launch ready systems</p><h2>Buy, sell, verify, chat and manage from one platform.</h2></section><div class="grid"><button class="card" data-route="marketplace"><span>Amazon-style buying</span><b>Spare parts checkout →</b></button><button class="card" data-route="sell"><span>OLX-style selling</span><b>Verified seller posting →</b></button><button class="card" data-route="admin"><span>Admin control</span><b>Approve & protect →</b></button></div><section class="section"><p class="eyebrow">Categories</p><h2>Everything for the agricultural field.</h2></section><div class="grid">${categories.map(c=>`<button class="card category" data-cat="${esc(c)}"><span>${esc(c)}</span><b>Explore →</b></button>`).join('')}</div>`}
function marketplace(){let f=S.filters; let list=S.products.filter(p=>(!f.q||(`${p.title} ${p.brand} ${p.model} ${p.category}`).toLowerCase().includes(f.q.toLowerCase()))&&(!f.category||p.category===f.category)&&(!f.state||p.state===f.state)&&(!f.brand||p.brand===f.brand)&&(!f.type||p.sale_type===f.type)); return `<section class="section"><p class="eyebrow">Marketplace</p><h2>Live listings from approved sellers.</h2></section><div class="filters"><input id="q" placeholder="Search products" value="${esc(f.q)}"><select id="type"><option value="">All Types</option><option value="machine" ${f.type==='machine'?'selected':''}>Machines</option><option value="spare_part" ${f.type==='spare_part'?'selected':''}>Spare Parts</option></select><select id="cat"><option value="">All Categories</option>${categories.map(c=>`<option ${f.category===c?'selected':''}>${esc(c)}</option>`)}</select><select id="brand"><option value="">All Brands</option>${brands.map(b=>`<option ${f.brand===b?'selected':''}>${esc(b)}</option>`)}</select><select id="state"><option value="">All States</option>${states.map(s=>`<option ${f.state===s?'selected':''}>${esc(s)}</option>`)}</select></div><section class="products">${list.map(productCard).join('')||'<div class="empty">No approved products yet. Sellers can submit listings from Sell page.</div>'}</section>`}

function getTrustBadges(obj={}){
  const role=String(obj.role||obj.seller_role||obj.seller_type||'').toLowerCase();
  const status=String(obj.verification_status||obj.status||'').toLowerCase();
  const rating=Number(obj.avg_rating||obj.rating||0);
  const views=Number(obj.views||obj.view_count||0);
  const listings=Number(obj.listing_count||obj.products_count||0);
  const arr=[];
  if(status==='approved'||status==='verified'||obj.verified)arr.push(['verified','Verified Seller','Identity checked']);
  if(role.includes('dealer')||obj.plan_name)arr.push(['dealer','Trusted Dealer','Dealer account']);
  if(rating>=4.5)arr.push(['rated','Top Rated','High buyer rating']);
  if(views>=50)arr.push(['popular','Popular Listing','High interest']);
  if(listings>=25)arr.push(['power','Power Seller','Active inventory']);
  if(!arr.length)arr.push(['new','New Seller','New profile']);
  return arr.slice(0,4);
}
function badgeMarkup(obj={},mini=false){return `<div class="trust-badges ${mini?'mini':''}">${getTrustBadges(obj).map(b=>`<span class="trust-badge ${b[0]}" title="${esc(b[2])}"><i></i>${esc(b[1])}</span>`).join('')}</div>`}

function primaryBadge(obj={}){return getTrustBadges(obj)[0]||['new','New Seller','New profile']}
function accountTheme(obj={}){let k=primaryBadge(obj)[0]; return ['verified','fast','safe'].includes(k)?'theme-verified':['dealer','rated','popular'].includes(k)?'theme-gold':k==='power'?'theme-dark':'theme-new'}
function sellerTitle(obj={}){return primaryBadge(obj)[1]||'Member'}
function sellerDocUrl(key){ if(!key)return ''; if(String(key).startsWith('http'))return key; try{return sb?.storage.from('verification-docs').getPublicUrl(key).data.publicUrl||''}catch(e){return ''} }
function sellerScore(s={}){let n=0; for(const k of ['aadhaar_front_url','aadhaar_back_url','shop_photo_url','aadhaar_front','aadhaar_back','shop_photo']) if(s[k]) n++; if(s.phone) n++; if(s.business_name) n++; return n}
function aiKycStatus(s={}){let score=sellerScore(s); if(String(s.status).includes('provisional'))return ['provisional','AI provisional']; if(score>=4)return ['provisional','AI suggests provisional approval']; if(score>=2)return ['review','AI needs manual review']; return ['weak','Missing documents'];}
function celebration(title='Approved',body='Status updated successfully'){let box=document.createElement('div');box.className='celebration';box.innerHTML=`<button class="celebration-close" aria-label="Close">×</button><div class="confetti left"></div><div class="confetti right"></div><div class="celebration-card"><p class="eyebrow">Harvester Parts</p><h2>${esc(title)}</h2><p>${esc(body)}</p></div>`;document.body.appendChild(box);box.querySelector('button').onclick=()=>box.remove();setTimeout(()=>box.remove(),8500)}
function adminNoticeSummary({sellers=[],products=[],reports=[]}={}){let total=(sellers?.length||0)+(products?.length||0)+(reports?.length||0); if(!total)return ''; return `<div class="admin-alert"><b>${total}</b><div><strong>Action needed</strong><p>${sellers.length} seller requests • ${products.length} product approvals • ${reports.length} reports</p></div></div>`}

function productCard(p){return `<article class="product"><button class="wish ${JSON.parse(localStorage.hp_wishlist||'[]').includes(String(p.id))?'saved':''}" data-wish="${p.id}" aria-label="Save product">♡</button><a href="#product/${p.id}"><img src="${img(p.image_url,p.title)}" onerror="this.src='${fallback(p.title)}'" alt="${esc(p.title)}"><div class="pbody"><div class="tags"><span class="tag">${p.sale_type==='spare_part'?'Spare Part':'Machine'}</span><span class="tag">${esc(p.condition||'Used')}</span></div>${badgeMarkup(p,true)}<h3>${esc(p.title)}</h3><p>${esc(p.brand||'')} ${esc(p.model||'')} • ${esc(p.district||'')}, ${esc(p.state||'')}</p><div class="price">${money(p.price)}</div></a><button class="btn small" data-product="${p.id}">${p.sale_type==='spare_part'?'Add to Cart':'Send Enquiry'}</button></div></article>`}
function product(id){let p=S.products.find(x=>String(x.id)===String(id)); if(!p)return `<div class="empty">Product not found.</div>`; let similar=S.products.filter(x=>x.id!==p.id&&x.category===p.category).slice(0,3); return `<section class="detail"><div><div class="gallery"><img src="${img(p.image_url,p.title)}" onerror="this.src='${fallback(p.title)}'" alt="${esc(p.title)}"></div><section class="section"><p class="eyebrow">Product Details</p><h2>${esc(p.title)}</h2><p>${esc(p.description||'Seller has not added a detailed description yet.')}</p><div class="specs">${[['Brand',p.brand],['Model',p.model],['Year',p.year],['Condition',p.condition],['Engine No.',p.engine_number],['Chassis No.',p.chassis_number],['Hours Used',p.hours_used],['Location',`${p.village||''} ${p.district||''}, ${p.state||''}`]].map(x=>`<div class="spec"><small>${esc(x[0])}</small><b>${esc(x[1]||'Not provided')}</b></div>`).join('')}</div></section><section class="section"><p class="eyebrow">Reviews</p><h2>Buyer feedback</h2><div id="reviewsBox"><div class="empty">Loading reviews...</div></div><button id="reviewBtn" class="ghost">Post Review</button><button id="reportBtn" class="ghost">Report Listing</button></section><section class="section"><p class="eyebrow">Similar Products</p><h2>More from this category</h2><div class="products">${similar.map(productCard).join('')||'<div class="empty">No similar products yet.</div>'}</div></section></div><aside class="card buybox"><p class="eyebrow">${p.sale_type==='spare_part'?'Checkout available':'Seller enquiry'}</p><h2>${money(p.price)}</h2><p>${esc(p.district||'')} ${esc(p.state||'')}</p>${badgeMarkup(p)}<button class="btn dark full" data-product="${p.id}">${p.sale_type==='spare_part'?'Add to Cart':'Send Enquiry'}</button><button class="btn full" data-buy="${p.id}">Buy Now</button><button class="ghost full" id="whatsappBtn">WhatsApp Seller</button><button class="ghost full" data-route="storefront/${p.seller_id}">View Seller Store</button></aside></section>`}
function sell(){if(!S.user)return loginRequired('Login to sell products'); if(!isSeller())return sellerApply(); return `<section class="section"><p class="eyebrow">Sell Product</p><h2>Post a machine or spare part.</h2></section><form id="productForm" class="form-card"><div class="forms"><input name="title" placeholder="Product title" required><select name="sale_type"><option value="machine">Machine / Implement</option><option value="spare_part">Spare Part</option></select><select name="category">${categories.map(c=>`<option>${esc(c)}</option>`)}</select><select name="brand">${brands.map(b=>`<option>${esc(b)}</option>`)}</select><input name="model" placeholder="Model"><input name="price" type="number" placeholder="Price ₹" required><input name="year" type="number" placeholder="Year"><input name="condition" placeholder="New / Used / Refurbished"><input name="engine_number" placeholder="Engine number"><input name="chassis_number" placeholder="Chassis number"><input name="hours_used" type="number" placeholder="Hours used"><select name="state">${states.map(s=>`<option>${esc(s)}</option>`)}</select><input name="district" placeholder="District"><input name="city" placeholder="City"><input name="village" placeholder="Village"><input name="image_url" placeholder="Image URL optional"><input name="image_file" type="file" accept="image/*"><textarea class="full" name="description" rows="5" placeholder="Product details, service history, included items"></textarea><button class="btn dark full">Submit for Admin Approval</button></div><p class="smalltxt">New products remain pending until admin approval.</p></form>`}
function sellerApply(){return `<section class="section"><p class="eyebrow">Seller Verification</p><h2>Only verified sellers can post products.</h2></section><form id="sellerForm" class="form-card"><div class="forms"><input name="business_name" placeholder="Business / Seller name" required><input name="phone" placeholder="Phone number" required><input name="address" placeholder="Full address" class="full"><label>Aadhaar front<input name="aadhaar_front" type="file" accept="image/*"></label><label>Aadhaar back<input name="aadhaar_back" type="file" accept="image/*"></label><label>Shop photo<input name="shop_photo" type="file" accept="image/*"></label><button class="btn dark full">Submit Verification</button></div><p class="smalltxt">Admin will review your documents before approval. Status: ${esc(S.seller?.status||'not submitted')}.</p></form>`}
function plans(){return `<section class="section"><p class="eyebrow">Seller Plans</p><h2>Plans from ₹999 to ₹15,999.</h2></section><div class="grid">${PLAN_LIST.map(p=>`<div class="card"><p class="eyebrow">${p[0]}</p><h2>${money(p[1])}</h2><p>${p[2]===9999?'Unlimited':p[2]} listings</p><p>${p[3]}</p><button class="btn" data-plan="${p[1]}" data-name="${p[0]}">Buy Plan</button></div>`).join('')}</div>`}
function badges(){
let mine=S.products.filter(p=>String(p.user_id)===String(authId()));
let profileStatus=S.seller?.status==='approved'||isAdmin();
let badgeData=[
  {k:'verified',t:'Verified Seller',d:'Aadhaar/shop verification approved by admin.',ok:profileStatus},
  {k:'dealer',t:'Trusted Dealer',d:'Dealer or premium seller profile enabled.',ok:String(S.profile?.role||'').toLowerCase()==='dealer'||isAdmin()},
  {k:'rated',t:'Top Rated',d:'Maintain 4.5+ buyer rating after successful deals.',ok:false},
  {k:'popular',t:'Popular Listing',d:'Earned when your listings receive strong buyer interest.',ok:mine.some(p=>Number(p.views||0)>50)},
  {k:'power',t:'Power Seller',d:'Post 25+ quality active listings.',ok:mine.length>=25},
  {k:'fast',t:'Fast Responder',d:'Reply quickly to buyer messages and enquiries.',ok:false},
  {k:'safe',t:'Safe Trader',d:'Clean account with no unresolved reports.',ok:!!S.user},
  {k:'launch',t:'Launch Member',d:'Early Harvester Parts account holder.',ok:!!S.user}
];
return `<section class="section"><p class="eyebrow">Rewards & Badges</p><h2>Minimal trust badges for buyers, sellers and dealers.</h2><p>Badges are shown on product cards, seller profiles and product pages to build confidence before a buyer contacts or purchases.</p></section><div class="badge-showcase">${badgeData.map(b=>`<article class="custom-badge-card ${b.ok?'earned':'locked'}"><div class="custom-badge ${b.k}"><span></span><b>${esc(b.t)}</b></div><h3>${esc(b.t)}</h3><p>${esc(b.d)}</p><strong>${b.ok?'Active':'Locked'}</strong></article>`).join('')}</div>`}
function cart(){let rows=S.cart.map(i=>({...i,p:S.products.find(p=>p.id===i.id)})).filter(x=>x.p); let total=rows.reduce((a,i)=>a+i.p.price*i.qty,0); return `<section class="section"><p class="eyebrow">Cart</p><h2>${rows.length} items</h2></section>${rows.map(i=>`<div class="cart-row"><img src="${img(i.p.image_url,i.p.title)}"><div><b>${esc(i.p.title)}</b><p>${money(i.p.price)}</p><div class="qty"><button class="circle" data-dec="${i.id}">−</button><b>${i.qty}</b><button class="circle" data-inc="${i.id}">+</button><button class="ghost" data-remove="${i.id}">Remove</button></div></div><div class="price">${money(i.p.price*i.qty)}</div></div>`).join('')||'<div class="empty">Cart is empty.</div>'}<aside class="card"><h2>Total ${money(total)}</h2><button class="btn dark" data-route="checkout">Checkout</button></aside>`}
function checkout(){if(!S.user)return loginRequired('Login before checkout'); let rows=S.cart.map(i=>({...i,p:S.products.find(p=>p.id===i.id)})).filter(x=>x.p), total=rows.reduce((a,i)=>a+i.p.price*i.qty,0); return `<section class="section"><p class="eyebrow">Checkout</p><h2>Place secure order.</h2></section><div class="checkout"><form id="checkoutForm" class="form-card"><div class="forms"><input name="name" placeholder="Full name" value="${esc(S.profile?.full_name||'')}" required><input name="phone" placeholder="Phone" value="${esc(S.profile?.phone||'')}" required><input class="full" name="address" placeholder="Delivery address" required></div><h3>Payment Method</h3><label class="payment-card"><input type="radio" name="method" value="razorpay" checked><b>Razorpay Online Payment</b></label><label class="payment-card"><input type="radio" name="method" value="seller"><b>Seller Confirmation / Enquiry</b></label><button class="btn dark full">Place Secure Order</button></form><aside class="card"><p class="eyebrow">Order Summary</p><h2>${money(total)}</h2><p>${rows.length} items</p><p class="smalltxt">Razorpay payments are saved as paid only after payment callback. Use server verification for final security.</p></aside></div>`}
function account(){if(!S.user)return loginRequired('Login to view account'); let p=S.profile||{}, theme=accountTheme({...p,...(S.seller||{})}), title=sellerTitle({...p,...(S.seller||{})}); return `<section class="section"><p class="eyebrow">My Account</p><h2>Your profile.</h2></section><div class="account-hero ${theme}"><div class="avatar big">${p.profile_image?`<img src="${p.profile_image}">`:(p.full_name||S.user.email||'H')[0]}</div><div><h2>${esc(p.full_name||S.user.email)} <span>${esc(title)}</span></h2><p>${esc(p.user_uid||'')} • ${esc(p.role||'user')}</p>${badgeMarkup({...p,...(S.seller||{})},true)}</div></div><form id="profileForm" class="form-card"><div class="forms"><div><input name="photo" type="file" accept="image/*"></div><input name="full_name" placeholder="Full name" value="${esc(p.full_name||'')}"><input name="phone" placeholder="Phone" value="${esc(p.phone||'')}"><select name="gender"><option value="">Gender</option><option ${p.gender==='Male'?'selected':''}>Male</option><option ${p.gender==='Female'?'selected':''}>Female</option><option ${p.gender==='Other'?'selected':''}>Other</option></select><input value="${esc(p.user_uid||'')}" readonly><input value="${esc(p.role||'user')}" readonly><button class="btn dark full">Save Profile</button><button type="button" class="ghost full" data-route="dashboard">Seller Dashboard</button><button type="button" class="ghost full" data-route="badges">Rewards & Badges</button><button type="button" class="ghost full" data-route="notifications">Notifications ${S.unread?'('+S.unread+')':''}</button>${isAdmin()?'<button type="button" class="ghost full" data-route="admin">Admin Panel</button>':''}<button type="button" class="ghost full" id="logout">Logout</button></div></form>`}
function dashboard(){if(!S.user)return loginRequired('Login first'); return `<section class="section"><p class="eyebrow">Seller Dashboard</p><h2>Products, leads and store.</h2></section><div class="admin-grid"><div class="admin-card"><b id="dashProducts">0</b><p>My Products</p></div><div class="admin-card"><b>${S.seller?.status||'not seller'}</b><p>Seller Status</p></div><div class="admin-card"><b>${S.profile?.role||'user'}</b><p>Account Role</p></div></div><section class="section"><h2>My Listings</h2><div id="myListings" class="products"></div></section>`}
function orders(){return `<section class="section"><p class="eyebrow">Orders</p><h2>My orders.</h2></section><div id="ordersList"></div>`}
function messages(){return `<section class="section"><p class="eyebrow">Messages</p><h2>Buyer and seller enquiries.</h2><form id="replyForm" class="form-card"><input name="receiver" placeholder="Receiver user id"><textarea name="message" placeholder="Message"></textarea><button class="btn dark">Send</button></form></section><div id="messageList"></div>`}
function notifications(){return `<section class="section"><p class="eyebrow">Notifications</p><h2>Updates and approvals.</h2></section><div id="notificationList"></div>`}
function storefront(id){let list=S.products.filter(p=>String(p.seller_id)===String(id)); return `<section class="section"><p class="eyebrow">Dealer Storefront</p><h2>Seller products.</h2><p>Seller ID: ${esc(id||'')}</p></section><div class="products">${list.map(productCard).join('')||'<div class="empty">No approved products for this seller yet.</div>'}</div>`}
function reports(){if(!isAdmin())return loginRequired('Admin only'); return `<section class="section"><p class="eyebrow">Reports</p><h2>Safety reports.</h2></section><div id="reportsList"></div>`}
function admin(){if(!S.user)return `<section class="section admin-login-box"><p class="eyebrow">Admin Login</p><h2>Login with your admin account.</h2><p>Use the same email/password you registered with, then set role = admin in Supabase.</p><button id="openLogin" class="btn">Login / Create Account</button></section>`; if(!isAdmin())return `<section class="section admin-login-box"><p class="eyebrow">Admin</p><h2>Access denied.</h2><p>You are logged in as <b>${esc(S.user.email||'user')}</b>, but this account is not admin.</p><p class="smalltxt">In Supabase run: update public.users set role='admin' where email='${esc(S.user.email||'YOUR_EMAIL')}';</p><span class="status-pill">Current role: ${esc(S.profile?.role||'user')}</span></section>`; return `<section class="section"><p class="eyebrow">Admin Panel</p><h2>Approvals, alerts and marketplace safety.</h2><div id="adminNotice"></div></section><div class="admin-grid"><div class="admin-card"><b>${S.counts.products}</b><p>Approved Products</p></div><div class="admin-card"><b>${S.counts.sellers}</b><p>Approved Sellers</p></div><div class="admin-card"><b>${S.unread}</b><p>Unread</p></div></div><section class="section"><h2>Pending approvals</h2><div id="adminPending" class="products"></div></section><section class="section"><h2>Reports</h2><div id="adminReports" class="grid"></div></section>`}
function policy(){return `<section class="legal"><p class="eyebrow">Policies</p><h2>Terms, privacy and seller agreement.</h2><p>Harvester Parts is a verified marketplace for agricultural machinery and spare parts. Sellers must provide accurate product details, ownership status, location, price and documents when requested.</p><h3>Seller Agreement</h3><p>Only verified sellers may publish products. Admin approval is required for sellers and listings. Fraudulent, duplicate, misleading or unsafe listings may be removed and accounts may be blocked.</p><h3>Buyer Policy</h3><p>Buyers should inspect machines before final high-value purchase. Spare part orders may use checkout where enabled. Heavy machinery enquiry flow connects buyer and seller.</p><h3>Refund Policy</h3><p>Refunds depend on payment status, seller confirmation, dispatch status and admin review.</p><h3>Privacy Policy</h3><p>User profile, verification and order data are stored in Supabase. Verification documents are private and only reviewed for approval.</p></section>`}

function wishlist(){
  let ids=JSON.parse(localStorage.hp_wishlist||'[]');
  let list=S.products.filter(p=>ids.includes(String(p.id))||ids.includes(p.id));
  return `<section class="section"><p class="eyebrow">Wishlist</p><h2>Saved machinery and spare parts.</h2></section><div class="products">${list.map(productCard).join('')||'<div class="empty">No saved products yet. Open any product and tap save.</div>'}</div>`
}
function ai(){return `<section class="section"><p class="eyebrow">AI Helper</p><h2>Ask Harvester Parts assistant.</h2><p>This helper can guide buyers, sellers and admins using your current live products. Add an OpenAI key later for advanced answers.</p></section><div class="form-card ai-panel"><div id="aiLog"><p><b>AI:</b> Tell me what machine, brand, budget or location you need.</p></div><form id="aiForm" class="coupon-row"><input name="q" placeholder="Example: tractor under 5 lakh in Punjab"><button class="btn">Ask</button></form><div class="grid" style="margin-top:14px"><button class="card ai-chip" data-ai="Find verified sellers near me">Find verified sellers</button><button class="card ai-chip" data-ai="Help me post a spare part listing">Help me sell</button><button class="card ai-chip" data-ai="What badges can I earn?">Explain badges</button></div></div>`}

function loginRequired(msg){return `<section class="section"><p class="eyebrow">Login Required</p><h2>${esc(msg)}</h2><button id="openLogin" class="btn">Login / Create Account</button></section>`}
function bindPage(){
  $$('.wish').forEach(b=>b.onclick=e=>{e.preventDefault();let ids=JSON.parse(localStorage.hp_wishlist||'[]'),id=String(b.dataset.wish);ids=ids.includes(id)?ids.filter(x=>x!==id):[...ids,id];localStorage.hp_wishlist=JSON.stringify(ids);b.classList.toggle('saved',ids.includes(id));toast(ids.includes(id)?'Saved to wishlist':'Removed from wishlist')});
  $('#aiForm')?.addEventListener('submit',e=>{e.preventDefault();let q=new FormData(e.target).get('q');aiAnswer(q)}); $$('.ai-chip').forEach(b=>b.onclick=()=>aiAnswer(b.dataset.ai)); $$('.category').forEach(b=>b.onclick=()=>{S.filters.category=b.dataset.cat;location.hash='marketplace'}); ['q','type','cat','brand','state'].forEach(id=>$('#'+id)?.addEventListener('input',e=>{let map={q:'q',type:'type',cat:'category',brand:'brand',state:'state'};S.filters[map[id]]=e.target.value;route()})); $$('[data-product]').forEach(b=>b.onclick=()=>handleProductAction(b.dataset.product)); $$('[data-buy]').forEach(b=>b.onclick=()=>{let p=S.products.find(x=>x.id===b.dataset.buy); if(p?.sale_type==='spare_part'){let i=S.cart.find(x=>x.id===p.id); i?i.qty++:S.cart.push({id:p.id,qty:1}); saveCart(); location.hash='checkout'} else handleProductAction(p.id)}); $('#openLogin')?.addEventListener('click',authModal); $('#sellerForm')?.addEventListener('submit',submitSeller); $('#productForm')?.addEventListener('submit',submitProduct); $('#checkoutForm')?.addEventListener('submit',submitCheckout); $('#profileForm')?.addEventListener('submit',saveProfile); $('#replyForm')?.addEventListener('submit',sendManualMessage); $('#logout')?.addEventListener('click',async()=>{await sb?.auth.signOut();S.user=null;S.profile=null;toast('Logged out');location.hash='home'}); $$('[data-inc]').forEach(b=>b.onclick=()=>{let i=S.cart.find(x=>x.id===b.dataset.inc);if(i)i.qty++;saveCart();route()}); $$('[data-dec]').forEach(b=>b.onclick=()=>{let i=S.cart.find(x=>x.id===b.dataset.dec);if(i)i.qty--;S.cart=S.cart.filter(x=>x.qty>0);saveCart();route()}); $$('[data-remove]').forEach(b=>b.onclick=()=>{S.cart=S.cart.filter(x=>x.id!==b.dataset.remove);saveCart();route()}); $$('[data-plan]').forEach(b=>b.onclick=()=>pay(b.dataset.name,+b.dataset.plan,()=>buyPlan(b.dataset.name,+b.dataset.plan))); $('#reviewBtn')?.addEventListener('click',submitReview); $('#reportBtn')?.addEventListener('click',submitReport); $('#whatsappBtn')?.addEventListener('click',whatsappSeller); if(location.hash.includes('admin'))loadAdmin(); if(location.hash.includes('orders'))loadOrders(); if(location.hash.includes('messages'))loadMessages(); if(location.hash.includes('notifications'))loadNotifications(); if(location.hash.includes('dashboard'))loadDashboard(); if(location.hash.includes('reports'))loadReports(); if(location.hash.includes('product/'))loadReviews(); }
function authModal(){const m=document.createElement('div');m.className='drawer open';m.innerHTML=`<button class="drawer-bg" data-x></button><section class="drawer-panel"><div class="drawer-head"><h2>Account Access</h2><button class="circle" data-x>×</button></div><div class="auth-tabs"><button type="button" class="tab active" data-mode="login">Login</button><button type="button" class="tab" data-mode="signup">Create Account</button></div><form id="authForm" class="form-card"><input name="name" placeholder="Full name (new account)"><input name="email" type="email" placeholder="Email" required><input name="password" type="password" placeholder="Password minimum 6 chars" required><button id="authSubmit" class="btn dark" style="width:100%">Login</button><p class="smalltxt" id="authHelp">Existing user? Login. New user? Tap Create Account.</p></form></section>`;document.body.appendChild(m);let mode='login';m.querySelectorAll('[data-x]').forEach(x=>x.onclick=()=>m.remove());m.querySelectorAll('[data-mode]').forEach(btn=>btn.onclick=()=>{mode=btn.dataset.mode;m.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active',t===btn));m.querySelector('#authSubmit').textContent=mode==='login'?'Login':'Create Account';});m.querySelector('#authForm').onsubmit=async e=>{e.preventDefault(); if(!sb)return toast('Add Supabase keys first'); await withLoading(mode==='login'?'Logging in...':'Creating account...',async()=>{let fd=new FormData(e.target), email=String(fd.get('email')).trim(), password=String(fd.get('password')); let res=mode==='login'?await sb.auth.signInWithPassword({email,password}):await sb.auth.signUp({email,password,options:{data:{full_name:fd.get('name')}}}); if(res.error)toast(res.error.message); else{m.remove();toast(mode==='login'?'Logged in':'Account created'); await auth(); route();}})}}
async function uploadFile(bucket,file,path){if(!file||!sb)return ''; let ext=file.name.split('.').pop(), key=`${path}-${Date.now()}.${ext}`; let {error}=await sb.storage.from(bucket).upload(key,file,{upsert:true}); if(error){toast(error.message);return ''} return bucket==='verification-docs'?key:sb.storage.from(bucket).getPublicUrl(key).data.publicUrl}
async function submitSeller(e){
  e.preventDefault();
  if(!sb)return toast('Add Supabase keys first');
  if(!S.user)return authModal();
  await withLoading('Checking documents and submitting verification...',async()=>{
    let fd=new FormData(e.target);
    let row={
      user_id:authId(),
      business_name:String(fd.get('business_name')||'').trim(),
      phone:String(fd.get('phone')||'').trim(),
      address:String(fd.get('address')||'').trim(),
      status:'pending',
      verification_status:'pending'
    };
    if(!row.business_name||!row.phone)return toast('Please enter seller name and phone number');
    for(const k of ['aadhaar_front','aadhaar_back','shop_photo']){
      let file=fd.get(k);
      if(file&&file.size){
        if(!file.type.startsWith('image/')){toast('Only image files are allowed for Aadhaar/shop verification'); return}
        if(file.size>(k==='shop_photo'?5:3)*1024*1024){toast((k==='shop_photo'?'Shop photo':'Aadhaar image')+' is too large. Please upload a smaller image.'); return}
        row[k]=await uploadFile('verification-docs',file,`verification/${authId()}/${k}`);
        if(!row[k])return;
      }
    }
    let ai=aiKycStatus(row);
    if(ai[0]==='provisional') row.status='provisional';
    row.ai_review_note=ai[1];
    let {error}=await sb.from('sellers').upsert(row,{onConflict:'user_id'});
    if(error){ console.error('Seller verification error:', error, row); toast(error.message||'Seller verification failed. Run database-clean-reset-full.sql once.'); return; }
    toast(row.status==='provisional'?'AI provisional verification submitted':'Verification submitted for review');
    await notifyAdmin('Seller verification request',`${row.business_name||S.user.email} submitted verification. AI status: ${ai[1]}`);
    await loadSeller();
    route();
  })
}
async function submitProduct(e){
  e.preventDefault();
  if(!S.user)return authModal();
  if(!S.seller?.id && !isAdmin())return toast('Seller verification is required before posting products');
  await withLoading('Submitting product for approval...',async()=>{
    let fd=new FormData(e.target);
    let image_url=String(fd.get('image_url')||'').trim(), file=fd.get('image_file');
    if(file&&file.size)image_url=await uploadFile('product-images',file,`products/${authId()}`);
    let row={
      seller_id:S.seller?.id||null,
      user_id:authId(),
      title:String(fd.get('title')||'').trim(),
      sale_type:fd.get('sale_type'),
      category:fd.get('category'),
      brand:fd.get('brand'),
      model:fd.get('model'),
      price:+fd.get('price')||0,
      year:+fd.get('year')||null,
      condition:fd.get('condition'),
      engine_number:fd.get('engine_number'),
      chassis_number:fd.get('chassis_number'),
      hours_used:+fd.get('hours_used')||null,
      state:fd.get('state'),district:fd.get('district'),city:fd.get('city'),village:fd.get('village'),
      description:fd.get('description'),image_url,status:'pending'
    };
    if(!row.title||!row.price)return toast('Please enter product title and price');
    let {error}=await sb.from('products').insert(row);
    if(error)toast(error.message);
    else{toast('Product submitted for admin approval'); await notifyAdmin('New product pending','A seller submitted a product for approval.'); location.hash='dashboard'}
  })
}
async function saveProfile(e){
  e.preventDefault();
  if(!S.user)return authModal();
  await withLoading('Saving profile...',async()=>{
    let fd=new FormData(e.target), profile_image=S.profile?.profile_image, file=fd.get('photo');
    if(file&&file.size)profile_image=await uploadFile('profile-images',file,`profiles/${authId()}`);
    let payload={full_name:fd.get('full_name'),phone:fd.get('phone'),gender:fd.get('gender'),profile_image,profile_completed:true};
    let {error}=await sb.from('users').update(payload).eq('auth_id',authId());
    if(error)toast(error.message); else{toast('Profile saved');await loadProfile();route();}
  })
}
async function submitCheckout(e){
  e.preventDefault();
  await withLoading('Preparing secure order...',async()=>{
    if(!S.cart.length)return toast('Cart is empty');
    let total=S.cart.reduce((a,i)=>{let p=S.products.find(x=>x.id===i.id);return a+(p?.price||0)*i.qty},0), method=new FormData(e.target).get('method');
    if(method==='razorpay')pay('Harvester Parts Order',total,(rzp)=>createOrder(total,'paid',rzp));
    else createOrder(total,'pending')
  })
}
async function createOrder(total,status,rzp={}){
  if(!S.user)return authModal();
  let payload={buyer_id:authId(),user_id:authId(),amount:total,status,payment_id:rzp.razorpay_payment_id||null,razorpay_order_id:rzp.razorpay_order_id||null};
  let {data,error}=await sb.from('orders').insert(payload).select().single();
  if(error)return toast(error.message);
  let items=S.cart.map(i=>{let p=S.products.find(x=>x.id===i.id);return{order_id:data.id,product_id:i.id,quantity:i.qty,price:p?.price||0}});
  if(items.length) await sb.from('order_items').insert(items);
  S.cart=[]; saveCart(); toast('Order placed'); location.hash='orders';
}
function pay(name,amount,success){if(window.Razorpay&&cfg.RAZORPAY_KEY_ID&&!cfg.RAZORPAY_KEY_ID.includes('YOUR_')) new Razorpay({key:cfg.RAZORPAY_KEY_ID,amount:amount*100,currency:'INR',name:'Harvester Parts',description:name,handler:async(res)=>{if(cfg.PAYMENT_VERIFY_URL){try{await fetch(cfg.PAYMENT_VERIFY_URL,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(res)});}catch(e){console.warn(e)}}success(res)}}).open(); else{toast('Razorpay key missing. Demo success.'); success({})}}
async function buyPlan(name,amount){if(!S.user)return authModal(); await sb.from('seller_plans').insert({user_id:authId(),plan_name:name,amount,status:'active'}); toast('Plan activated')}
async function handleProductAction(id){let p=S.products.find(x=>String(x.id)===String(id)); if(!p)return; if(p.sale_type==='spare_part'){let i=S.cart.find(x=>x.id===p.id); i?i.qty++:S.cart.push({id:p.id,qty:1}); saveCart(); toast('Added to cart')} else {await createMessage(p,'I am interested in this product. Please contact me.'); toast('Enquiry sent to seller')}}
async function createMessage(p,text){if(!S.user)return authModal(); if(!sb)return; let receiver=p.user_id||p.seller_user_id||p.seller_id; await sb.from('messages').insert({product_id:p.id,sender_id:authId(),receiver_id:receiver,message:text}); await sb.from('notifications').insert({user_id:receiver,title:'New product enquiry',message:text,type:'message'});}
async function sendManualMessage(e){e.preventDefault(); let fd=new FormData(e.target); if(!fd.get('receiver')||!fd.get('message'))return toast('Receiver and message required'); await sb.from('messages').insert({sender_id:authId(),receiver_id:fd.get('receiver'),message:fd.get('message')}); toast('Message sent')}
async function submitReview(){if(!S.user)return authModal(); let comment=prompt('Write your review'); if(!comment)return; let rating=Number(prompt('Rating 1 to 5','5')||5); let id=location.hash.split('/')[1]; await sb.from('reviews').insert({product_id:id,user_id:authId(),rating:Math.max(1,Math.min(5,rating)),comment}); toast('Review posted'); loadReviews();}
async function loadReviews(){let id=location.hash.split('/')[1], box=$('#reviewsBox'); if(!box||!sb)return; let {data}=await sb.from('reviews').select('*').eq('product_id',id).order('created_at',{ascending:false}); box.innerHTML=(data||[]).map(r=>`<div class="card"><b>${'★'.repeat(r.rating||5)}</b><p>${esc(r.comment)}</p></div>`).join('')||'<div class="empty">No reviews yet.</div>'}
async function submitReport(){if(!S.user)return authModal(); let reason=prompt('Why are you reporting this listing?'); if(!reason)return; let id=location.hash.split('/')[1]; await sb.from('reports').insert({target_type:'product',target_id:id,reporter_id:authId(),reason,status:'open'}); toast('Report submitted for admin review')}
function whatsappSeller(){let id=location.hash.split('/')[1],p=S.products.find(x=>String(x.id)===String(id)),num=cfg.WHATSAPP_NUMBER||'919999999999'; open(`https://wa.me/${num}?text=${encodeURIComponent('I am interested in '+(p?.title||'your product'))}`,'_blank')}
async function loadOrders(){if(!sb||!S.profile)return; let {data}=await sb.from('orders').select('*').eq('buyer_id',authId()).order('created_at',{ascending:false}); $('#ordersList').innerHTML=(data||[]).map(o=>`<div class="card"><b>${o.id.slice(0,8)}</b><p>${money(o.amount||o.total||0)} • ${esc(o.status)}</p><p>${new Date(o.created_at).toLocaleString()}</p></div>`).join('')||'<div class="empty">No orders yet.</div>'}
async function loadMessages(){if(!sb||!S.profile)return; let {data}=await sb.from('messages').select('*, products(title)').or(`sender_id.eq.${authId()},receiver_id.eq.${authId()}`).order('created_at',{ascending:false}); $('#messageList').innerHTML=(data||[]).map(m=>`<div class="card"><b>${esc(m.products?.title||'Product enquiry')}</b><p>${esc(m.message)}</p><small>${new Date(m.created_at).toLocaleString()}</small></div>`).join('')||'<div class="empty">No messages yet.</div>'}
async function loadNotifications(){if(!sb||!S.profile)return; let {data}=await sb.from('notifications').select('*').eq('user_id',authId()).order('created_at',{ascending:false}); $('#notificationList').innerHTML=(data||[]).map(n=>`<div class="card"><b>${esc(n.title)}</b><p>${esc(n.message||n.body||'')}</p><small>${new Date(n.created_at).toLocaleString()}</small></div>`).join('')||'<div class="empty">No notifications yet.</div>'; await sb.from('notifications').update({is_read:true}).eq('user_id',authId()); await loadUnread();}
async function loadDashboard(){if(!sb||!S.profile)return; let {data}=await sb.from('products').select('*').eq('user_id',authId()).order('created_at',{ascending:false}); $('#dashProducts').textContent=(data||[]).length; $('#myListings').innerHTML=(data||[]).map(p=>`<div class="product"><img src="${img(p.image_url,p.title)}"><div class="pbody"><h3>${esc(p.title)}</h3><p>${esc(p.status)} • ${money(p.price)}</p><button class="ghost" data-delete-product="${p.id}">Delete</button></div></div>`).join('')||'<div class="empty">No listings yet.</div>'; $$('[data-delete-product]').forEach(b=>b.onclick=async()=>{if(confirm('Delete this listing?')){await sb.from('products').delete().eq('id',b.dataset.deleteProduct);toast('Deleted');loadDashboard();}})}
async function loadReports(){if(!sb||!isAdmin())return; let {data}=await sb.from('reports').select('*').order('created_at',{ascending:false}); $('#reportsList').innerHTML=(data||[]).map(r=>`<div class="card"><b>${esc(r.target_type||'Report')}</b><p>${esc(r.reason)}</p><p>${esc(r.status)}</p></div>`).join('')||'<div class="empty">No reports.</div>'}
async function notifyAdmin(title,message){if(!sb)return; let {data}=await sb.from('users').select('auth_id').eq('role','admin'); if(data?.length) await sb.from('notifications').insert(data.map(a=>({user_id:a.auth_id,title,message,type:'admin'})));}
async function loadAdmin(){if(!sb||!isAdmin())return; let {data:products}=await sb.from('products').select('*').in('status',['pending','provisional']); let {data:sellers}=await sb.from('sellers').select('*, users(full_name,email,phone,user_uid,role,profile_image)').in('status',['pending','provisional']); let {data:reports}=await sb.from('reports').select('*').eq('status','open'); $('#adminNotice').innerHTML=adminNoticeSummary({sellers:sellers||[],products:products||[],reports:reports||[]}); $('#adminPending').innerHTML=[...(sellers||[]).map(s=>{let ai=aiKycStatus(s), front=sellerDocUrl(s.aadhaar_front_url||s.aadhaar_front), back=sellerDocUrl(s.aadhaar_back_url||s.aadhaar_back), shop=sellerDocUrl(s.shop_photo_url||s.shop_photo);return `<div class="card seller-review"><div class="seller-review-head"><div><h3>${esc(s.business_name||'Seller Request')}</h3><p>${badgeMarkup({...s,verification_status:s.status},true)}</p><span class="status-pill ${ai[0]}">${esc(ai[1])}</span></div><button class="ghost small" data-provisional-seller="${s.id}">AI Provisional</button></div><div class="review-details"><p><b>Name:</b> ${esc(s.users?.full_name||'Not provided')}</p><p><b>Email:</b> ${esc(s.users?.email||'')}</p><p><b>Phone:</b> ${esc(s.phone||s.users?.phone||'Not provided')}</p><p><b>User ID:</b> ${esc(s.users?.user_uid||s.user_id||'')}</p><p><b>Address:</b> ${esc(s.address||[s.city,s.district,s.state].filter(Boolean).join(', ')||'Not provided')}</p><p><b>Current status:</b> ${esc(s.status||'pending')}</p></div><div class="doc-grid">${front?`<a target="_blank" href="${front}"><span>Aadhaar Front</span><img src="${front}" onerror="this.replaceWith(document.createTextNode('Open document'))"></a>`:''}${back?`<a target="_blank" href="${back}"><span>Aadhaar Back</span><img src="${back}" onerror="this.replaceWith(document.createTextNode('Open document'))"></a>`:''}${shop?`<a target="_blank" href="${shop}"><span>Shop Photo</span><img src="${shop}" onerror="this.replaceWith(document.createTextNode('Open document'))"></a>`:''}</div><div class="row-actions"><button class="btn small" data-approve-seller="${s.id}" data-user="${s.user_id}">Approve</button><button class="ghost small" data-reject-seller="${s.id}">Reject</button></div></div>`}),...(products||[]).map(p=>`<div class="product seller-review"><img src="${img(p.image_url,p.title)}"><div class="pbody"><h3>${esc(p.title)}</h3><p>${esc(p.category||'')} • ${esc(p.brand||'')} • ${money(p.price)}</p><p>${esc(p.description||'No description')}</p><div class="review-details"><p><b>Engine:</b> ${esc(p.engine_number||'Not provided')}</p><p><b>Chassis:</b> ${esc(p.chassis_number||'Not provided')}</p><p><b>Location:</b> ${esc([p.city,p.district,p.state].filter(Boolean).join(', ')||'Not provided')}</p><p><b>Status:</b> ${esc(p.status||'pending')}</p></div><button class="btn small" data-approve-product="${p.id}">Approve Product</button><button class="ghost small" data-reject-product="${p.id}">Reject Product</button></div></div>`)].join('')||'<div class="empty">Nothing pending.</div>'; $('#adminReports').innerHTML=(reports||[]).map(r=>`<div class="card"><b>${esc(r.target_type||'Report')}</b><p>${esc(r.reason)}</p><small>${esc(r.target_id||'')}</small><button class="btn small" data-close-report="${r.id}">Mark Resolved</button></div>`).join('')||'<div class="empty">No open reports.</div>'; $$('[data-provisional-seller]').forEach(b=>b.onclick=async()=>{await sb.from('sellers').update({status:'provisional'}).eq('id',b.dataset.provisionalSeller);toast('AI provisional status applied');loadAdmin()}); $$('[data-approve-seller]').forEach(b=>b.onclick=async()=>{await sb.from('sellers').update({status:'approved'}).eq('id',b.dataset.approveSeller); await sb.from('users').update({role:'seller'}).eq('auth_id',b.dataset.user); await sb.from('notifications').insert({user_id:b.dataset.user,title:'Seller approved',message:'Congratulations. Your Harvester Parts seller account is active.',type:'approval'}); celebration('Seller Approved','This seller can now post and manage products.'); await loadCounts();loadAdmin()}); $$('[data-reject-seller]').forEach(b=>b.onclick=async()=>{await sb.from('sellers').update({status:'rejected'}).eq('id',b.dataset.rejectSeller);toast('Seller rejected');loadAdmin()}); $$('[data-approve-product]').forEach(b=>b.onclick=async()=>{await sb.from('products').update({status:'approved'}).eq('id',b.dataset.approveProduct);celebration('Product Approved','The listing is now live on the marketplace.');await loadProducts();loadAdmin()}); $$('[data-reject-product]').forEach(b=>b.onclick=async()=>{await sb.from('products').update({status:'rejected'}).eq('id',b.dataset.rejectProduct);toast('Product rejected');loadAdmin()}); $$('[data-close-report]').forEach(b=>b.onclick=async()=>{await sb.from('reports').update({status:'resolved'}).eq('id',b.dataset.closeReport);toast('Report resolved');loadAdmin()})}

function aiAnswer(q){let log=$('#aiLog'); if(!log||!q)return; let t=String(q).toLowerCase(); let matches=S.products.filter(p=>(`${p.title} ${p.category} ${p.brand} ${p.state} ${p.district}`).toLowerCase().includes(t.split(' ')[0]||'')); let ans='I can help you search products, explain seller verification, coupons, shipping and badges.'; if(t.includes('sell')||t.includes('post'))ans='To sell, login → Sell Product → submit seller verification → after admin approval, post machine or spare part with images, price, weight and location.'; else if(t.includes('badge'))ans='Badges are earned from verification, dealer plan, good ratings, fast replies and strong listing activity.'; else if(matches.length)ans='I found related products: '+matches.slice(0,3).map(p=>p.title).join(', ')+'. Open Marketplace for details.'; log.innerHTML+=`<p><b>You:</b> ${esc(q)}</p><p><b>AI:</b> ${esc(ans)}</p>`; log.scrollTop=log.scrollHeight;}

function openDrawer(){ $('#drawer').classList.add('open'); $('#drawer').setAttribute('aria-hidden','false'); if(S.user){let p={...(S.profile||{}),...(S.seller||{})}, theme=accountTheme(p), title=sellerTitle(p); $('#drawerAccount').className='drawer-account '+theme; $('#drawerAccount').innerHTML=`<b>${esc(S.profile?.full_name||S.user.email)} <span class="drawer-title">${esc(title)}</span></b><p>${esc(S.profile?.user_uid||'')} • ${esc(S.profile?.role||'user')}</p>${badgeMarkup(p,true)}<div class="drawer-actions"><button class="btn small" data-route="account">My Account</button><button class="ghost small" id="drawerLogout">Logout</button></div>`} else {$('#drawerAccount').className='drawer-account'; $('#drawerAccount').innerHTML=`<b>Welcome</b><p>Login to buy, sell and manage orders.</p><button class="btn small" id="drawerLogin">Login</button>`} $('#drawerLogin')?.addEventListener('click',()=>{closeDrawer();authModal()}); $('#drawerLogout')?.addEventListener('click',async()=>{await sb?.auth.signOut(); closeDrawer(); S.user=null;S.profile=null;toast('Logged out');route()});}
function closeDrawer(){ $('#drawer')?.classList.remove('open'); $('#drawer')?.setAttribute('aria-hidden','true')}
init();
})();
